<script setup lang="ts">
import { computed,onMounted,reactive,ref } from 'vue'
import { ElMessage,ElMessageBox } from 'element-plus'
import { DataAnalysis,Download,Edit,Plus,Position,Refresh,Setting,User } from '@element-plus/icons-vue'
import { listDocuments,type GeologicalDocument } from '@/api/documents'
import { deleteUser,downloadAnalysisReport,downloadExport,getAnalysisReport,listLlmConfigs,listLogs,listTasks,listUsers,pushToOneMap,restoreDemoData,saveLlmConfig,saveUser,type AdminUser,type AnalysisReport,type LlmConfig,type SystemLog,type UserInput } from '@/api/admin'

type Tab='exports'|'users'|'tasks'|'models'|'logs'
const tab=ref<Tab>('exports'),loading=ref(true),users=ref<AdminUser[]>([]),tasks=ref<GeologicalDocument[]>([]),configs=ref<LlmConfig[]>([]),logs=ref<SystemLog[]>([]),documents=ref<GeologicalDocument[]>([])
const dialog=ref(false),editing=ref<number>(),userForm=reactive<UserInput>({username:'',password:'',displayName:'',role:'USER',enabled:true})
const exportForm=reactive({documentId:undefined as number|undefined,format:'xlsx',dataset:'entities'}),exporting=ref(false)
const configForms=ref<Array<LlmConfig&{apiKey?:string}>>([]),reportOpen=ref(false),reportLoading=ref(false),report=ref<AnalysisReport>()
const completedTasks=computed(()=>tasks.value.filter(item=>item.graphStatus==='COMPLETED').length)
const failedTasks=computed(()=>tasks.value.filter(item=>[item.status,item.entityStatus,item.knowledgeStatus,item.spatialStatus,item.graphStatus].includes('FAILED')).length)
const tabs:[Tab,string][]=[['exports','成果交付'],['users','用户管理'],['tasks','任务管理'],['models','模型配置'],['logs','调用日志']]

async function load(){loading.value=true;try{const[us,ts,cs,ls,docs]=await Promise.all([listUsers(),listTasks(),listLlmConfigs(),listLogs(),listDocuments({page:1,size:100,status:'PARSED'})]);users.value=us;tasks.value=ts;configs.value=cs;configForms.value=cs.map(item=>({...item,apiKey:''}));logs.value=ls;documents.value=docs.records;if(!exportForm.documentId)exportForm.documentId=docs.records[0]?.id}catch(error){ElMessage.error(message(error))}finally{loading.value=false}}
function openUser(user?:AdminUser){editing.value=user?.id;Object.assign(userForm,user?{username:user.username,password:'',displayName:user.displayName,role:user.role,enabled:user.enabled}:{username:'',password:'',displayName:'',role:'USER',enabled:true});dialog.value=true}
async function submitUser(){try{await saveUser(userForm,editing.value);ElMessage.success('用户已保存');dialog.value=false;users.value=await listUsers()}catch(error){ElMessage.error(message(error))}}
async function removeUser(user:AdminUser){try{await ElMessageBox.confirm(`确认删除用户“${user.displayName}”？`,'删除用户',{type:'warning'});await deleteUser(user.id);users.value=await listUsers()}catch(error){if(error!=='cancel'&&error!=='close')ElMessage.error(message(error))}}
async function saveConfig(form:LlmConfig&{apiKey?:string}){try{await saveLlmConfig({provider:form.provider,baseUrl:form.baseUrl,modelName:form.modelName,apiKey:form.apiKey||undefined,temperature:form.temperature,promptTemplate:form.promptTemplate,enabled:form.enabled});ElMessage.success(`${form.provider} 配置已保存并应用`);configs.value=await listLlmConfigs();configForms.value=configs.value.map(item=>({...item,apiKey:''}))}catch(error){ElMessage.error(message(error))}}
async function runExport(){if(!exportForm.documentId)return;exporting.value=true;try{await downloadExport(exportForm.documentId,exportForm.format,exportForm.dataset);ElMessage.success('成果文件已生成')}catch(error){ElMessage.error(message(error))}finally{exporting.value=false}}
async function restoreDemo(){try{const document=await restoreDemoData();ElMessage.success(`已恢复标准演示资料：${document.name}`);await load();exportForm.documentId=document.id}catch(error){ElMessage.error(message(error))}}
async function pushOneMap(){if(!exportForm.documentId)return ElMessage.warning('请先选择来源资料');try{const result=await pushToOneMap(exportForm.documentId);ElMessage.success(result.message)}catch(error){ElMessage.error(message(error))}}
async function previewReport(){if(!exportForm.documentId)return ElMessage.warning('请先选择来源资料');reportLoading.value=true;try{report.value=await getAnalysisReport(exportForm.documentId);reportOpen.value=true}catch(error){ElMessage.error(message(error))}finally{reportLoading.value=false}}
async function exportReport(){if(!exportForm.documentId)return ElMessage.warning('请先选择来源资料');try{await downloadAnalysisReport(exportForm.documentId);ElMessage.success('分析报告 PDF 已生成')}catch(error){ElMessage.error(message(error))}}
function stage(task:GeologicalDocument){const states=[task.status,task.entityStatus,task.knowledgeStatus,task.spatialStatus,task.graphStatus];if(states.includes('FAILED'))return'FAILED';if(task.graphStatus==='COMPLETED')return'COMPLETED';if(states.some(value=>value==='PARSING'||value==='EXTRACTING'||value==='SYNCING'))return'RUNNING';return'PENDING'}
function message(error:unknown){return error instanceof Error?error.message:'操作失败'}
onMounted(load)
</script>

<template>
  <div class="admin-page" v-loading="loading">
    <header class="admin-header"><div><span>Phase 8 · DELIVERY CONTROL</span><h1>成果与系统控制台</h1><p>在一个可审计的工作台完成成果交付、模型配置与运行治理。</p></div><div><b>{{users.length}}</b><small>用户</small><b>{{completedTasks}}</b><small>完整任务</small><b>{{failedTasks}}</b><small>异常</small></div></header>
    <nav class="admin-tabs"><button v-for="item in tabs" :key="item[0]" type="button" :class="{active:tab===item[0]}" @click="tab=item[0]">{{item[1]}}</button></nav>
    <main class="admin-content">
      <section v-if="tab==='exports'" class="export-studio">
        <div><span>RESEARCH PACKAGE</span><h2>结构化成果与分析报告</h2><p>选择一份资料，导出结构化成果、生成分析报告，或推送至地球科学“一张图”。</p></div>
        <div class="export-form"><label>来源资料<el-select v-model="exportForm.documentId"><el-option v-for="doc in documents" :key="doc.id" :label="doc.name" :value="doc.id"/></el-select></label><label>文件格式<el-select v-model="exportForm.format"><el-option label="Excel 工作簿" value="xlsx"/><el-option label="CSV 表格" value="csv"/><el-option label="JSON 全量包" value="json"/><el-option label="GeoJSON 空间包" value="geojson"/></el-select></label><label v-if="exportForm.format==='csv'">数据集<el-select v-model="exportForm.dataset"><el-option label="实体" value="entities"/><el-option label="属性" value="attributes"/><el-option label="关系" value="relations"/><el-option label="空间对象" value="spatial"/></el-select></label><button type="button" :disabled="exporting" @click="runExport"><el-icon><Download/></el-icon>{{exporting?'正在生成…':'生成并下载'}}</button></div>
        <div class="format-grid"><article v-for="item in [['XLSX','四张工作表'],['CSV','UTF-8 / 可筛选'],['JSON','完整证据结构'],['GEOJSON','FeatureCollection']]" :key="item[0]"><strong>{{item[0]}}</strong><span>{{item[1]}}</span></article></div>
        <div class="delivery-actions"><article><el-icon><DataAnalysis/></el-icon><div><strong>空间化分析报告</strong><span>预览结论并导出中文 PDF</span></div><button type="button" :disabled="reportLoading" @click="previewReport">预览</button><button type="button" @click="exportReport">下载 PDF</button></article><article><el-icon><Position/></el-icon><div><strong>地球科学“一张图”</strong><span>推送当前资料 GeoJSON 成果</span></div><button type="button" @click="pushOneMap">推送成果</button></article><article><el-icon><Refresh/></el-icon><div><strong>标准演示数据</strong><span>恢复完整实体、关系和点线面数据</span></div><button type="button" @click="restoreDemo">恢复演示</button></article></div>
      </section>
      <section v-else-if="tab==='users'" class="admin-panel"><header><div><span>ACCESS CONTROL</span><h2>系统用户</h2></div><button type="button" @click="openUser()"><el-icon><Plus/></el-icon>新增用户</button></header><div class="user-grid"><article v-for="item in users" :key="item.id"><el-icon><User/></el-icon><div><strong>{{item.displayName}}</strong><small>@{{item.username}}</small></div><span :class="item.role.toLowerCase()">{{item.role}}</span><em :class="{off:!item.enabled}">{{item.enabled?'启用':'停用'}}</em><button type="button" @click="openUser(item)"><el-icon><Edit/></el-icon></button><button type="button" @click="removeUser(item)">删除</button></article></div></section>
      <section v-else-if="tab==='tasks'" class="admin-panel"><header><div><span>PIPELINE MONITOR</span><h2>全流程任务</h2></div><button type="button" @click="load"><el-icon><Refresh/></el-icon>刷新</button></header><div class="task-table"><header><span>资料</span><span>解析</span><span>实体</span><span>知识</span><span>空间</span><span>图谱</span><span>总体</span></header><article v-for="task in tasks" :key="task.id"><strong>{{task.name}}</strong><span>{{task.status}}</span><span>{{task.entityStatus||'PENDING'}}</span><span>{{task.knowledgeStatus||'PENDING'}}</span><span>{{task.spatialStatus||'PENDING'}}</span><span>{{task.graphStatus||'PENDING'}}</span><b :class="stage(task).toLowerCase()">{{stage(task)}}</b></article></div></section>
      <section v-else-if="tab==='models'" class="admin-panel"><header><div><span>MODEL RUNTIME</span><h2>LLM 配置</h2></div><p>API Key 保存后不回显；启用配置会实时推送至 AI 服务。</p></header><div class="model-grid"><article v-for="form in configForms" :key="form.provider"><header><strong>{{form.provider}}</strong><span :class="{ready:form.keyConfigured}">{{form.keyConfigured?'KEY 已配置':'等待 KEY'}}</span></header><label>API 地址<input v-model="form.baseUrl"/></label><label>模型名称<input v-model="form.modelName"/></label><label>API Key<input v-model="form.apiKey" type="password" placeholder="留空则保持原密钥"/></label><label>Temperature<input v-model.number="form.temperature" type="number" min="0" max="2" step="0.1"/></label><label>Prompt 模板<textarea v-model="form.promptTemplate" rows="4"/></label><div><el-switch v-model="form.enabled" active-text="启用"/><button type="button" @click="saveConfig(form)"><el-icon><Setting/></el-icon>保存并应用</button></div></article></div></section>
      <section v-else class="admin-panel"><header><div><span>AUDIT TRAIL</span><h2>AI 调用日志</h2></div><button type="button" @click="listLogs().then(value=>logs=value)"><el-icon><Refresh/></el-icon>刷新</button></header><div class="log-table"><header><span>时间</span><span>功能</span><span>模型</span><span>状态</span><span>耗时</span><span>异常</span></header><article v-for="log in logs" :key="log.id"><span>{{new Date(log.createTime).toLocaleString()}}</span><strong>{{log.functionName||log.action}}</strong><span>{{log.model||log.provider||'—'}}</span><b :class="log.status.toLowerCase()">{{log.status}}</b><span>{{log.elapsedMs??'—'}} ms</span><em>{{log.errorMessage||'—'}}</em></article></div></section>
    </main>
    <el-dialog v-model="reportOpen" title="地质文本空间化分析报告" width="min(960px,94vw)"><div v-if="report" class="report-preview"><header><span>ANALYSIS REPORT</span><h2>{{report.document.name}}</h2><p>{{report.document.region||'未填写区域'}} · {{report.document.year||'未填写年份'}} · 生成于 {{new Date(report.generatedAt).toLocaleString()}}</p></header><div class="report-metrics"><span><b>{{report.summary.entityCount}}</b>实体</span><span><b>{{report.summary.attributeCount}}</b>属性</span><span><b>{{report.summary.relationCount}}</b>关系</span><span><b>{{report.summary.spatialObjectCount}}</b>空间对象</span></div><section><h3>资料摘要</h3><p>{{report.document.summary||'暂无摘要'}}</p></section><section><h3>主要识别结果</h3><div class="report-tags"><span v-for="item in report.entities.slice(0,18)" :key="item.id">{{item.standardName||item.entityName}} · {{item.entityType}}</span></div></section><section><h3>空间化成果</h3><p v-for="item in report.spatialObjects" :key="item.id">{{item.name}} / {{item.geometryType}} / {{Number(item.centerLongitude).toFixed(5)}}, {{Number(item.centerLatitude).toFixed(5)}}</p></section></div><template #footer><el-button @click="reportOpen=false">关闭</el-button><el-button type="primary" @click="exportReport">下载 PDF</el-button></template></el-dialog>
    <el-dialog v-model="dialog" :title="editing?'编辑用户':'新增用户'" width="min(520px,92vw)"><el-form label-position="top"><el-form-item label="用户名"><el-input v-model="userForm.username"/></el-form-item><el-form-item label="显示名称"><el-input v-model="userForm.displayName"/></el-form-item><el-form-item :label="editing?'新密码（留空不修改）':'密码'"><el-input v-model="userForm.password" type="password"/></el-form-item><el-form-item label="角色"><el-select v-model="userForm.role"><el-option label="管理员" value="ADMIN"/><el-option label="普通用户" value="USER"/></el-select></el-form-item><el-switch v-model="userForm.enabled" active-text="启用账号"/></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="submitUser">保存</el-button></template></el-dialog>
  </div>
</template>

<style scoped>
.admin-page{padding:30px;background:#ebe7dc;min-height:calc(100vh - 82px);color:#153c35}.admin-header{display:flex;justify-content:space-between;gap:24px}.admin-header span,.admin-panel header span,.export-studio>div>span{font:700 10px ui-monospace;letter-spacing:.18em;color:#b56b32}.admin-header h1{margin:7px 0;font:600 36px Georgia}.admin-header p{margin:0;color:#63746d}.admin-header>div:last-child{display:grid;grid-template-columns:repeat(3,auto);gap:4px 18px;align-content:center;text-align:right}.admin-header b{font:27px Georgia;color:#b45e2f}.admin-header small{grid-row:2}.admin-tabs{display:flex;margin-top:24px;border-bottom:1px solid #b9b2a3}.admin-tabs button{border:0;background:transparent;padding:13px 22px;color:#68766f}.admin-tabs button.active{background:#123d36;color:white}.admin-content{margin-top:18px}.export-studio{background:#123d36;color:#edf0e8;display:grid;grid-template-columns:1fr 1fr;gap:28px;padding:38px}.export-studio h2,.admin-panel h2{font:600 29px Georgia;margin:6px 0}.export-studio p{color:#afc0b9;line-height:1.7}.export-form{display:grid;gap:13px}.export-form label,.model-grid label{display:grid;gap:6px;font-size:11px;letter-spacing:.08em}.export-form button,.admin-panel>header button,.model-grid button,.delivery-actions button{border:0;background:#e99a4c;color:#153c35;padding:11px 14px;font-weight:700}.format-grid{grid-column:1/-1;display:grid;grid-template-columns:repeat(4,1fr);border-top:1px solid #ffffff24;padding-top:20px}.format-grid article{display:grid;border-right:1px solid #ffffff24;padding:4px 18px}.format-grid strong{font:24px Georgia;color:#eca159}.format-grid span{font-size:11px;color:#aebdb7}.delivery-actions{grid-column:1/-1;display:grid;gap:8px}.delivery-actions article{display:grid;grid-template-columns:34px 1fr auto auto;gap:10px;align-items:center;border-top:1px solid #ffffff20;padding:13px 0}.delivery-actions article>svg{font-size:23px;color:#eca159}.delivery-actions article>div{display:grid}.delivery-actions span{font-size:11px;color:#aebdb7}.delivery-actions button{padding:8px 12px}.admin-panel{background:#f6f2e9;border:1px solid #d1c9ba;padding:24px}.admin-panel>header{display:flex;justify-content:space-between;align-items:center;margin-bottom:18px}.admin-panel>header h2{margin:5px 0}.user-grid{display:grid;gap:8px}.user-grid article{display:grid;grid-template-columns:36px 1fr 80px 70px 40px 55px;align-items:center;background:white;border:1px solid #ded7cb;padding:13px}.user-grid article>svg{font-size:24px;color:#397063}.user-grid div{display:grid}.user-grid button{border:0;background:transparent;color:#765744}.task-table>header,.task-table article{display:grid;grid-template-columns:minmax(220px,2fr) repeat(6,1fr);gap:10px;padding:11px;border-bottom:1px solid #ddd5c7;align-items:center;font-size:12px}.completed,.success{color:#23805a}.failed{color:#b44539}.running{color:#bd702e}.model-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:16px}.model-grid article{background:white;border:1px solid #d9d1c3;padding:20px;display:grid;gap:12px}.model-grid article>header,.model-grid article>div{display:flex;justify-content:space-between;align-items:center}.model-grid input,.model-grid textarea{border:1px solid #c9c0b1;background:#f8f5ef;padding:10px}.log-table>header,.log-table article{display:grid;grid-template-columns:170px 1.5fr 1fr 80px 80px 1.5fr;gap:10px;padding:11px;border-bottom:1px solid #ddd5c7;align-items:center;font-size:11px}.report-preview{color:#173e36}.report-preview>header{border-left:5px solid #d8813e;padding-left:18px}.report-preview>header span{font:700 10px ui-monospace;letter-spacing:.18em;color:#b56b32}.report-preview h2{font:600 29px Georgia;margin:5px 0}.report-metrics{display:grid;grid-template-columns:repeat(4,1fr);margin:22px 0;border:1px solid #d8d0c2}.report-metrics span{display:grid;text-align:center;padding:14px;border-right:1px solid #d8d0c2}.report-metrics b{font:28px Georgia;color:#b45e2f}.report-preview section{border-top:1px solid #ded7ca;padding-top:10px}.report-tags{display:flex;flex-wrap:wrap;gap:7px}.report-tags span{background:#e7eee9;padding:6px 9px;font-size:12px}@media(max-width:850px){.admin-page{padding:14px}.admin-header{display:block}.export-studio{grid-template-columns:1fr;padding:22px}.format-grid{grid-template-columns:repeat(2,1fr)}.delivery-actions article{grid-template-columns:30px 1fr}.delivery-actions button{grid-row:2}.model-grid{grid-template-columns:1fr}.task-table,.log-table{overflow:auto}.task-table>header,.task-table article{min-width:850px}.log-table>header,.log-table article{min-width:780px}.report-metrics{grid-template-columns:repeat(2,1fr)}}
</style>
